-- DROP Table SubDistrict;
-- DROP Table District;
-- DROP Table Division;

CREATE TABLE Division(
	Id int IDENTITY(1,1) NOT NULL,
	Name nvarchar(500) NOT NULL,
	Code nvarchar(50) NULL,
	GPSLatitude decimal(15, 12) NULL,
	GPSLongitude decimal(15, 12) NULL
	CONSTRAINT PK_Division PRIMARY KEY (Id)
);

-- DELETE FROM Division; DBCC CHECKIDENT ('dbo.Division',RESEED, 0);


CREATE TABLE District(
	Id int IDENTITY(1,1) NOT NULL,
	Name nvarchar(500) NOT NULL,
	Code nvarchar(50) NULL,
	DivisionId int NULL,
	GPSLatitude decimal(15, 12) NULL,
	GPSLongitude decimal(15, 12) NULL
	CONSTRAINT PK_District PRIMARY KEY (Id)
);
ALTER TABLE District ADD CONSTRAINT FK_District_DivisionId FOREIGN KEY(DivisionId) REFERENCES Division (Id);

-- DELETE FROM District; DBCC CHECKIDENT ('dbo.District',RESEED, 0);


CREATE TABLE SubDistrict(
	Id int IDENTITY(1,1) NOT NULL,
	Name nvarchar(500) NOT NULL,
	Code nvarchar(50) NULL,
	AreaType nvarchar(50) NULL, -- ENUM: "Upazila", "Thana", "City Corporation", "Municipality"
	DistrictId int NULL,
	GPSLatitude decimal(15, 12) NULL,
	GPSLongitude decimal(15, 12) NULL
	CONSTRAINT PK_SubDistrict PRIMARY KEY (Id)
);
ALTER TABLE SubDistrict ADD CONSTRAINT FK_SubDistrict_DistrictId FOREIGN KEY(DistrictId) REFERENCES District (Id);

